{"code": "import json
import re

# Get Swift files data
swift_files_path = locals()['var_functions.query_db:20']
with open(swift_files_path, 'r') as f:
    swift_files = json.load(f)

# Function to extract copy count from repo_data_description
def extract_copy_count(description):
    # Look for patterns like "duplicated X times", "appearing X times", "copied X times"
    patterns = [
        r'duplicated\s+(\d+)\s+times',
        r'appearing\s+(\d+)\s+times',
        r'copied\s+(\d+)\s+times',
        r'repeated\s+(\d+)\s+times'
    ]

    for pattern in patterns:
        match = re.search(pattern, description, re.IGNORECASE)
        if match:
            return int(match.group(1))
    return 0

# Process files to find the one with max copy count
max_copies = 0
file_with_max_copies = None

for file_info in swift_files:
    copies = extract_copy_count(file_info.get('repo_data_description', ''))
    if copies > max_copies:
        max_copies = copies
        file_with_max_copies = file_info

print('__RESULT__:')
print(json.dumps({
    'file': file_with_max_copies,
    'max_copies': max_copies
}, indent=2))"}

